import React, { useState } from "react";

export default function Poke(props) {
  const [ poke, setPoke ] = useState(props.match.params.name);
  const [ sprite, setSprite ] = useState([]);
  const [ stats, setStats ] = useState([]);
  const [ types, setTypes ] = useState([]);
  const [ height, setHeight ] = useState('');
  const [ weight, setWeight ] = useState('');
  const [ order, setOrder ] = useState('');
  const [loading, setLoading] = useState(false);
  if (!loading) {
    fetch(`https://pokeapi.co/api/v2/pokemon/${poke}`)
      .then(response => response.json())
      .then(res => {
        setSprite(res.sprites);
        setStats(res.stats.map(item => item));
        setTypes(res.types.map(item => item));
        setHeight(res.height);
        setWeight(res.weight);
        setOrder(res.order);
        setLoading(true);
        console.log(types)
      });
  }
  return (
    <div>
      {loading ? (
        <div>
          <h2>#{order} {poke}</h2>
          <div id="pokeData">
            <div className="sprite">
              <img src={sprite.front_default} alt={poke} />
            </div>
            <div className="basic">
              <ul className="types">
                {types.map(item => (<li className={item.type.name} key={item.type.name}>{item.type.name}</li>))}
              </ul>
              <p>Height: {height}</p>
              <p>Weight: {weight}</p>
            </div>
          </div>
          <div className="stats">
            <ul className="statList">
              {stats.map(item => (<li key={item.stat.name}>{item.stat.name}: {item.base_stat}</li>))}
            </ul>
          </div>
        </div>

      ) : (
        <div id="loader">
          <div className="inner"><div className="bar" /></div>
          <p>Loading...</p>
        </div>
      )}
    </div>
  );
}
